boot.artifact:
// 先挂 iframe 再动态加载主题,冷缓存时也有稳定可见的预览载体
const frame = document.createElement('iframe');
frame.style.cssText = `width:100%;height:${spec.height ?? 900}px;border:0`;
frame.srcdoc = '<!doctype html><p style="font:14px system-ui">Rendering résumé…</p>';
document.getElementById('resume').appendChild(frame);
const { render } = await import('https://cdn.jsdelivr.net/npm/jsonresume-theme-even@0.26.1/+esm');
frame.srcdoc = render(data.resume);

